<?php
namespace App\Http\Middleware;use App\Models\Hotel;use Closure;use Illuminate\Http\Request;use Symfony\Component\HttpFoundation\Response;
class SetCurrentHotel{public function handle(Request$request,Closure$next):Response{$actor=$request->user();abort_unless($actor?->hotel_id,403,'This account is not assigned to a hotel.');$hotel=Hotel::with('subscription')->findOrFail($actor->hotel_id);abort_unless($hotel->status==='active',403,'This hotel account is inactive.');app()->instance('currentHotel',$hotel);if(!$request->isMethodSafe()&&(!$hotel->subscription||$hotel->subscription->isReadOnly())){return$request->expectsJson()?response()->json(['message'=>'This subscription is read-only. Subscribe or contact the platform administrator to restore changes.','subscription_state'=>$hotel->subscription?->lifecycleState()??'inactive'],403):back()->withErrors(['subscription'=>'This subscription is read-only. Subscribe or contact the platform administrator to restore changes.']);}return$next($request);}}
